                                    <div class="event-calendar-links">
                                        <?php
                                        $s = je_ev_local_dt(get_post_meta($pid, 'je_event_start', true));
                                        $e_dt = je_ev_local_dt(get_post_meta($pid, 'je_event_end', true));
                                        $tz = wp_timezone_string();
