        <script>
        (function() {
            const card = document.getElementById('<?php echo esc_js($instance_id); ?>');
            if (!card) return;
            
            const setText = (selector, value, show) => {
                const el = card.querySelector(selector);
                if (!el) return;
                if (typeof show === 'boolean') {
                    el.style.display = show ? '' : 'none';
                }
                if (value !== null && value !== undefined) {
                    el.textContent = value;
                }
            };
            
            const setCta = (value, href, disabled) => {
                const cta = card.querySelector('[data-role="cta"]');
                if (!cta) return;
                cta.textContent = value;
                cta.href = disabled ? '#' : href;
                if (disabled) {
                    cta.classList.add('is-disabled');
                    cta.setAttribute('aria-disabled', 'true');
                    cta.removeAttribute('target');
                    cta.removeAttribute('rel');
                } else {
                    cta.classList.remove('is-disabled');
                    cta.removeAttribute('aria-disabled');
                    cta.setAttribute('target', '_blank');
                    cta.setAttribute('rel', 'noopener noreferrer');
                }
            };
            
            const updatePricing = (billing) => {
                const prefix = billing === '5year' ? 'fiveYear' : 'yearly';
                const price = card.dataset[`${prefix}Price`];
                const retail = card.dataset[`${prefix}Retail`];
                const orderForm = card.dataset[`${prefix}OrderForm`];
                const billingLabel = card.dataset[`${prefix}Billing`];
                const cta = card.dataset[`${prefix}Cta`];
                const savings = card.dataset[`${prefix}Savings`];
                const showSavings = card.dataset[`${prefix}ShowSavings`] === '1';
                const badge = card.dataset[`${prefix}Badge`];
                const badgeEnd = card.dataset[`${prefix}BadgeEnd`];
                const showBadge = card.dataset[`${prefix}ShowBadge`] === '1';
                const disabled = card.dataset[`${prefix}Disabled`] === '1';
                
                setText('[data-role="price-amount"]', price ? Number(price).toLocaleString() : '0');
                setText('[data-role="retail-price"]', retail ? '$' + Number(retail).toLocaleString() : '', showSavings);
                setText('[data-role="billing-label"]', billingLabel || '');
                setText('[data-role="savings"]', savings || '', showSavings);
                
                const badgeWrap = card.querySelector('[data-role="badge"]');
                if (badgeWrap) {
                    badgeWrap.style.display = showBadge ? '' : 'none';
                    setText('[data-role="badge-text"]', badge || '');
                    setText('[data-role="badge-end"]', badgeEnd || '', !!badgeEnd);
                }
                
                setCta(cta || '', orderForm || '#', disabled);
            };
            
            const toggleButtons = card.querySelectorAll('.alm-memb-sale-toggle-btn');
            if (toggleButtons.length) {
                toggleButtons.forEach(btn => {
                    btn.addEventListener('click', () => {
                        toggleButtons.forEach(other => other.classList.remove('is-active'));
                        btn.classList.add('is-active');
                        updatePricing(btn.dataset.billing);
                    });
                });
            }
        })();
        </script>
        <?php
        return ob_get_clean();
    }
    
    /**
     * Black Friday 2025 Page Shortcode
     * Displays the top section of the Black Friday 2025 landing page
     */
    public function black_friday_page_shortcode($atts) {
        // Parse shortcode attributes
        $atts = shortcode_atts(array(
            'video' => 'false',
            'video_url' => '',
            'splash_text' => 'Click to play video',
            'hide_doorbuster' => 'false'
        ), $atts);
        
        $hide_doorbuster = ($atts['hide_doorbuster'] === 'true' || $atts['hide_doorbuster'] === '1');
        
        $show_video = ($atts['video'] === 'true' || $atts['video'] === '1');
        
        // Determine video URL for fvplayer
        $video_url = '';
        if ($show_video) {
            if (!empty($atts['video_url'])) {
                $video_url = esc_url_raw($atts['video_url']);
                
                // Convert YouTube embed URL to watch URL if needed (fvplayer works better with watch URLs)
                if (strpos($video_url, 'youtube.com/embed/') !== false) {
                    // Extract video ID from embed URL
                    preg_match('/embed\/([^"&?\/\s]{11})/', $video_url, $matches);
                    if (!empty($matches[1])) {
                        $video_id = $matches[1];
                        $video_url = 'https://www.youtube.com/watch?v=' . $video_id;
                    }
                }
            } else {
                // Default video if no URL provided
                $video_url = 'https://www.youtube.com/watch?v=C0DPdy98e4c';
            }
        }
        
        // Get splash text
        $splash_text = !empty($atts['splash_text']) ? esc_attr($atts['splash_text']) : 'Click to play video';
        
        // Get dates from membership pricing settings and check if sales are enabled/active
        $settings = get_option('je_membership_pricing_settings', array());
        $today = current_time('Y-m-d');
        
        // Get doorbuster and sale end dates from any tier (they should be the same across tiers)
        // Try premier first, then studio, then essentials
        $doorbuster_end_date = null;
        $sale_end_date = null;
        $doorbuster_enabled = false;
        $sale_enabled = false;
        $doorbuster_active = false;
        $sale_active = false;
        
        $tiers_to_check = array('premier', 'studio', 'essentials');
        foreach ($tiers_to_check as $tier) {
            if (isset($settings[$tier])) {
                $tier_data = $settings[$tier];
                
                // Check doorbuster - get date if enabled
                if (!empty($tier_data['doorbuster_enabled']) && !empty($tier_data['doorbuster_end_date'])) {
                    $doorbuster_enabled = true;
                    if (empty($doorbuster_end_date)) {
                        $doorbuster_end_date = $tier_data['doorbuster_end_date'];
                    }
                    // Check if doorbuster is currently active
                    if (!empty($tier_data['doorbuster_start_date'])) {
                        $doorbuster_start = $tier_data['doorbuster_start_date'];
                        $doorbuster_end = $tier_data['doorbuster_end_date'];
                        if ($today >= $doorbuster_start && $today <= $doorbuster_end) {
                            $doorbuster_active = true;
                        }
                    }
                }
                
                // Check sale - get date if enabled
                if (!empty($tier_data['sale_enabled']) && !empty($tier_data['sale_end_date'])) {
                    $sale_enabled = true;
                    if (empty($sale_end_date)) {
                        $sale_end_date = $tier_data['sale_end_date'];
                    }
                    // Check if sale is currently active
                    if (!empty($tier_data['sale_start_date'])) {
                        $sale_start = $tier_data['sale_start_date'];
                        $sale_end = $tier_data['sale_end_date'];
                        if ($today >= $sale_start && $today <= $sale_end) {
                            $sale_active = true;
                        }
                    }
                }
                
                // If we have both dates, we can break
                if ($doorbuster_end_date && $sale_end_date) {
                    break;
                }
            }
        }
        
        // Fallback to hardcoded dates if settings are not available (for display purposes)
        if (empty($doorbuster_end_date)) {
            $doorbuster_end_date = '2025-11-28';
        }
        if (empty($sale_end_date)) {
            $sale_end_date = '2025-12-03';
        }
        
        
        ob_start();
